import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { View, TextInput, Button, Text, ActivityIndicator } from 'react-native';

const addressSchema = z.object({
  fullName: z.string().min(2, 'Nom trop court'),
  phone: z.string().regex(/^\+237[0-9]{9}$/, 'Format: +237XXXXXXXXX'),
  street: z.string().min(5, 'Adresse trop courte'),
  city: z.string().min(2, 'Ville requise'),
  postalCode: z.string().optional(),
  country: z.string().min(2, 'Pays requis'),
});

export default function AddressForm({ onSubmit, initialData, isLoading }) {
  const { control, handleSubmit, formState: { errors } } = useForm({
    resolver: zodResolver(addressSchema),
    defaultValues: initialData || { country: 'Cameroun' }
  });

  return (
    <View>
      <TextInput placeholder="Nom complet" {...control.register('fullName')} />
      {errors.fullName && <Text>{errors.fullName.message}</Text>}

      <TextInput placeholder="Téléphone (+237XXXXXXXXX)" {...control.register('phone')} />
      {errors.phone && <Text>{errors.phone.message}</Text>}

      <TextInput placeholder="Rue / Quartier" {...control.register('street')} />
      <TextInput placeholder="Ville" {...control.register('city')} />
      <TextInput placeholder="Code postal (optionnel)" {...control.register('postalCode')} />
      <TextInput placeholder="Pays" {...control.register('country')} />

      {isLoading ? <ActivityIndicator /> : <Button title="Enregistrer" onPress={handleSubmit(onSubmit)} />}
    </View>
  );
}
