import { useState, useEffect } from 'react';
import { View, Button, Alert, ActivityIndicator } from 'react-native';
import MapView, { Marker } from 'react-native-maps';
import * as Location from 'expo-location';

export default function AddressMapPicker({ onLocationSelect }) {
  const [region, setRegion] = useState(null);
  const [markerCoord, setMarkerCoord] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    (async () => {
      const { status } = await Location.requestForegroundPermissionsAsync();
      if (status !== 'granted') {
        Alert.alert('Permission refusée', 'Impossible d\'obtenir votre position');
        setLoading(false);
        return;
      }
      const location = await Location.getCurrentPositionAsync({});
      const { latitude, longitude } = location.coords;
      setRegion({ latitude, longitude, latitudeDelta: 0.01, longitudeDelta: 0.01 });
      setMarkerCoord({ latitude, longitude });
      setLoading(false);
    })();
  }, []);

  const reverseGeocode = async (lat, lng) => {
    const results = await Location.reverseGeocodeAsync({ latitude: lat, longitude: lng });
    if (results.length > 0) {
      const addr = results[0];
      return `${addr.street || ''} ${addr.district || ''}, ${addr.city || ''}, ${addr.region || ''}`;
    }
    return '';
  };

  const handleConfirm = async () => {
    if (!markerCoord) return;
    const addressText = await reverseGeocode(markerCoord.latitude, markerCoord.longitude);
    onLocationSelect(markerCoord, addressText);
  };

  if (loading) return <ActivityIndicator size="large" />;

  return (
    <View style={{ flex: 1 }}>
      <MapView
        style={{ flex: 1 }}
        region={region}
        onRegionChangeComplete={setRegion}
      >
        {markerCoord && (
          <Marker
            coordinate={markerCoord}
            draggable
            onDragEnd={(e) => setMarkerCoord(e.nativeEvent.coordinate)}
            title="Votre adresse"
          />
        )}
      </MapView>
      <Button title="Valider cette adresse" onPress={handleConfirm} />
    </View>
  );
}
