const syncPendingAddresses = async () => {
  const { pendingOps, addresses } = useAddressStore.getState();
  if (pendingOps.length === 0) return;

  const netInfo = await NetInfo.fetch();
  if (!netInfo.isConnected) return;

  for (const op of pendingOps) {
    try {
      let response;
      switch (op.type) {
        case 'CREATE':
          response = await api.post('/addresses', op.address);
          useAddressStore.getState().updateAddressAfterSync(op.id, response.data);
          break;
        case 'UPDATE':
          response = await api.put(`/addresses/${op.address.id}`, op.address);
          if (response.data.version > op.address.version) {
            // Conflit détecté, on prend la version serveur
            useAddressStore.getState().resolveConflict(op.address.id, response.data);
          }
          break;
        case 'DELETE':
          await api.delete(`/addresses/${op.addressId}`);
          break;
      }
      useAddressStore.getState().removePendingOp(op.id);
    } catch (error) {
      if (op.retryCount >= 5) {
        useAddressStore.getState().markOpAsFailed(op.id);
      } else {
        useAddressStore.getState().incrementRetry(op.id);
      }
    }
  }
};
